#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char s[1005]; scanf("%s",s);
        int len=strlen(s);
        long long total=1+len; // load + prints
        for(int i=1;i<len;i++){
            int diff=(s[i]-s[i-1]);
            if(diff<0) diff+=26;
            total+=diff;
        }
        if(total<=11LL*len) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

