    int T; if(!(cin>>T)) return 0;
    while(T--){
        string s; cin>>s;
        int n=s.size();
        long long total=1LL+n; // load + prints
        for(int i=1;i<n;i++){
            int diff=s[i]-s[i-1];
            if(diff<0) diff+=26;
            total+=diff;
        }
        cout<<(total<=11LL*n?"YES":"NO")<<'\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for(int t=0;t<T;t++){
            String s = br.readLine().trim();
            int n = s.length();
            long total = 1L + n; // load + prints
            for(int i=1;i<n;i++){
                int diff = s.charAt(i) - s.charAt(i-1);
                if(diff<0) diff += 26;
                total += diff;
            }
            out.append(total <= 11L * n ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

